code: # Magic header identifying a DSPy cache blob, followed by a 1-byte codec selector.
# Values written without this header predate the compression feature and are treated
# as raw pickled bytes for backward compatibility.
_CACHE_BLOB_MAGIC = b"DSPC"
_CACHE_BLOB_CODECS = {None: 0x00, "gzip": 0x01, "zlib": 0x02}
_CACHE_BLOB_CODECS_BY_ID = {v: k for k, v in _CACHE_BLOB_CODECS.items()}


def _encode_disk_value(value: Any, compress: Optional[str]) -> bytes:
    payload = cloudpickle.dumps(value)
    if compress == "gzip":
        payload = gzip.compress(payload)
    elif compress == "zlib":
        payload = zlib.compress(payload)
    return _CACHE_BLOB_MAGIC + bytes([_CACHE_BLOB_CODECS[compress]]) + payload


def _decode_disk_value(data: Any) -> Any:
    if not isinstance(data, (bytes, bytearray)) or data[:4] != _CACHE_BLOB_MAGIC:
        # Legacy raw pickle written before the compression feature existed.
        return data

    codec = _CACHE_BLOB_CODECS_BY_ID.get(data[4])
    payload = data[5:]
    if codec == "gzip":
        payload = gzip.decompress(payload)
    elif codec == "zlib":
        payload = zlib.decompress(payload)
    return cloudpickle.loads(payload)
